// Parse Telegram command
const text = input.message_text || '';
let command = 'chat';
let params = '';

if (text.startsWith('/')) {
  const parts = text.split(' ');
  command = parts[0].toLowerCase().replace(/@.*/, '');
  params = parts.slice(1).join(' ');
} else {
  params = text;
}

const commands = {
  '/start': 'start', '/niche': 'set_niche', '/brand': 'set_brand',
  '/research': 'research', '/create': 'create', '/post': 'post',
  '/analytics': 'analytics', '/report': 'report', '/monetize': 'monetize',
  '/trends': 'trends', '/competitors': 'competitors', '/hooks': 'hooks',
  '/hashtags': 'hashtags', '/schedule': 'schedule', '/repurpose': 'repurpose',
  '/health': 'health', '/milestones': 'milestones', '/status': 'status', '/help': 'help'
};

return {
  route: commands[command] || 'chat',
  command: command,
  params: params,
  chatId: input.chat_id,
  username: input.username,
  firstName: input.first_name
};
